cd /home/runner/work/yyds-harness/yyds-harness && tail -20 .yoyo/state/events.jsonl 2>/dev/null | python3 -c "
import sys, json
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        e = json.loads(line)
        ts = e.get('ts', '')[-12:] if e.get('ts') else ''
        kind = e.get('event', e.get('type', '?'))
        payload = e.get('payload', {})
        if isinstance(payload, dict) and 'reason' in payload:
            print(f'{ts} {kind} reason={payload[\"reason\"]}')
        elif isinstance(payload, dict) and 'exit_code' in payload:
            print(f'{ts} {kind} exit_code={payload[\"exit_code\"]}')
        else:
            print(f'{ts} {kind}')
    except:
        print(f'PARSE ERROR: {line[:80]}')
"

